  ('aboriginal-57f41407-moex-00212', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '「各級各類學校相關課程及教材，應採多元文化觀點，並納入原住民族歷史文化及價值觀，以增進族 群間之瞭解及尊重。」請問上述內容係規定在那一部法規範？', '["中華民國憲法增修條文", "文化部組織法", "國家語言發展法", "原住民族教育法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
