  ('aboriginal-57f41407-moex-00214', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '下列有關原住民族教育法的用詞定義，何者有誤？', '["原住民族教育：指原住民族之一般教育及民族教育之統稱", "民族教育：指依原住民族文化特性，對原住民學生所實施之民族知識教育", "原住民族學校：指原住民學生達一定人數或比率之高級中等以下學校", "原住民族教育師資：指於原住民族學校、原住民重點學校或原住民教育班擔任原住民族教育課程教 學之師資"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00215', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民族基本法第19條規定，原住民得在原住民族地區及經中央原住民族主管機關公告之海域 依法從事下列非營利行為，下列何者錯誤？', '["獵捕非保育類動物", "採集野生菇類", "採取土石", "養魚"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00216', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民族教育法第11條，中央政府應寬列預算，專款辦理原住民族教育；其經費編列，合計不 得少於中央教育主管機關預算總額的多少比率？', '["百分之九點六", "百分之五點八", "百分之一點九", "百分之一點二"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00217', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '下列有關原住民族傳統智慧創作保護條例規定內容的敘述，何者有誤？', '["智慧創作應經主管機關認定並登記，始受本條例之保護", "智慧創作專用權，包括智慧創作財產權及智慧創作人格權", "智慧創作專用權可以任意拋棄", "智慧創作專用權，應永久保護之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00218', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '陳小明為阿美族，民國112年大學畢業後準備參加公務人員特種考試原住民族三等考試，但他必須要 先取得原住民族語言能力認證才能參加考試，請問這是依據那一部法規範的規定？', '["原住民族基本法", "原住民族語言發展法", "原住民族語言能力認證辦法", "原住民族語言發展法施行細則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00219', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民族教育法第19條，地方政府應設立任務編組性質之原住民族教育資源中心，有關原住民 族教育資源中心的設置規定與工作任務，何者錯誤？', '["辦理原住民族教育課程、教材與教學方法之研發及推廣", "協助各地方政府主管之學校，發展符合當地原住民族之民族教育課程規劃與評量方式", "負責各地方政府辦理原住民族教育統計與教育成果評量與管理", "原住民族教育資源中心所需經費，由中央教育主管機關及中央原住民族主管機關分別編列預算酌予 補助"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00220', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '請問民國108年12月26日成立之「財團法人原住民族語言研究發展基金會」是依據那一部法規範成 立的？', '["原住民族基本法", "原住民族語言發展法", "原住民族傳統智慧創作保護條例", "中華民國憲法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
